import{_ as a,a as i}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as t,o,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Accesso WebDAV al sito (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Safety/webdav-site-access.md","filePath":"it-IT/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),r={name:"it-IT/Safety/webdav-site-access.md"};function s(d,e,c,p,u,m){return o(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="accesso-webdav-al-sito-beta" tabindex="-1">Accesso WebDAV al sito (Beta) <a class="header-anchor" href="#accesso-webdav-al-sito-beta" aria-label="Permalink to &quot;Accesso WebDAV al sito (Beta)&quot;">​</a></h1><p>L&#39;impostazione WebDAV in Sicurezza espone il tuo sito ImgBed come endpoint WebDAV.</p><p>Dopo l&#39;abilitazione, puoi usare Windows, macOS, file manager mobile o qualunque client compatibile WebDAV per sfogliare, caricare, eliminare e gestire file ImgBed come una cartella remota.</p><p>Questo è l&#39;accesso WebDAV del sito. È diverso dal canale di archiviazione WebDAV in Impostazioni di caricamento: il canale di upload salva file su un servizio WebDAV di terze parti, mentre questa impostazione fa offrire WebDAV direttamente al tuo sito ImgBed.</p><h2 id="dove-configurare" tabindex="-1">Dove configurare <a class="header-anchor" href="#dove-configurare" aria-label="Permalink to &quot;Dove configurare&quot;">​</a></h2><p>Apri il pannello admin e vai a:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Impostazioni disponibili:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="a-cosa-serve" tabindex="-1">A cosa serve <a class="header-anchor" href="#a-cosa-serve" aria-label="Permalink to &quot;A cosa serve&quot;">​</a></h2><p>Dopo aver abilitato WebDAV, ImgBed espone un URL fisso:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>Usa questo URL per connetterti alla directory dei file ImgBed.</p><p>Casi d&#39;uso tipici:</p><ul><li>sfogliare file ImgBed direttamente dal file manager del computer.</li><li>trascinare immagini nella cartella WebDAV per caricarle.</li><li>organizzare cartelle ImgBed dal file manager locale.</li><li>usare software compatibile WebDAV per sincronizzare o gestire immagini.</li><li>accedere ai contenuti ImgBed senza aprire il pannello admin.</li></ul><h2 id="impostazioni" tabindex="-1">Impostazioni <a class="header-anchor" href="#impostazioni" aria-label="Permalink to &quot;Impostazioni&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>Attiva l&#39;endpoint WebDAV.</p><p>Quando è disattivato, i client non possono connettersi via WebDAV.</p><h3 id="username-e-password" tabindex="-1">Username e Password <a class="header-anchor" href="#username-e-password" aria-label="Permalink to &quot;Username e Password&quot;">​</a></h3><p>Queste credenziali vengono usate dai client WebDAV durante la connessione.</p><p>Usa nome utente e password dedicati per WebDAV. Non riutilizzare la password admin o la password di upload.</p><p>Se uno dei due campi è vuoto, i client WebDAV non potranno connettersi correttamente.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Decide quale URL immagine i client WebDAV preferiscono in lettura.</p><p>Scelte comuni:</p><table tabindex="0"><thead><tr><th>Modalità</th><th>Descrizione</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed sceglie in base al contesto. Consigliato per l&#39;uso normale.</td></tr><tr><td>Original</td><td>Preferisce le immagini originali.</td></tr><tr><td>Thumbnail</td><td>Preferisce le miniature. Utile per anteprime rapide.</td></tr></tbody></table><p>Se non sei sicuro, lascia <code>Smart loading</code>.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Il canale predefinito viene usato per gli upload WebDAV.</p><p>Quando copi file nella directory WebDAV da Windows o da un altro client, ImgBed li carica tramite il canale di upload selezionato.</p><p>Se non è selezionato un canale predefinito, la navigazione può funzionare, ma gli upload possono fallire.</p><h2 id="accedere-a-webdav-in-windows-11" tabindex="-1">Accedere a WebDAV in Windows 11 <a class="header-anchor" href="#accedere-a-webdav-in-windows-11" aria-label="Permalink to &quot;Accedere a WebDAV in Windows 11&quot;">​</a></h2><p>Windows 11 può aggiungere WebDAV come percorso di rete.</p><ol><li>Apri <code>This PC</code>.</li><li>Scegli <code>Add a network location</code>.</li><li>Inserisci <code>https://your-domain.com/dav</code>.</li><li>Inserisci username e password WebDAV quando richiesto.</li><li>Completa la procedura. La directory WebDAV potrà essere aperta in File Explorer.</li></ol><p><img src="'+a+'" alt="Aggiungi WebDAV in Windows 11" loading="lazy"></p><p>Dopo l&#39;aggiunta, la directory WebDAV compare in Esplora file. Puoi aprire, copiare e gestire file come in una cartella normale.</p><p><img src="'+i+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="operazioni-supportate" tabindex="-1">Operazioni supportate <a class="header-anchor" href="#operazioni-supportate" aria-label="Permalink to &quot;Operazioni supportate&quot;">​</a></h2><p>Dopo una connessione riuscita, di solito puoi:</p><ul><li>vedere file e cartelle.</li><li>caricare file.</li><li>creare cartelle.</li><li>rinominare file o cartelle.</li><li>spostare file.</li><li>eliminare file.</li></ul><p>WebDAV è adatto per accesso quotidiano e gestione leggera. Per spostamenti grandi, eliminazioni massive o organizzazioni complesse, usa il pannello admin.</p><h2 id="gestione-dispositivi-login" tabindex="-1">Gestione dispositivi login <a class="header-anchor" href="#gestione-dispositivi-login" aria-label="Permalink to &quot;Gestione dispositivi login&quot;">​</a></h2><p>Le connessioni WebDAV riuscite compaiono anche nella scheda WebDAV di Login Device Management.</p><p>Puoi controllare i client WebDAV e forzare offline vecchi dispositivi quando serve.</p><p>Se cambi username o password WebDAV, i vecchi client devono accedere di nuovo.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-continua-a-chiedere-username-e-password" tabindex="-1">Windows continua a chiedere username e password <a class="header-anchor" href="#windows-continua-a-chiedere-username-e-password" aria-label="Permalink to &quot;Windows continua a chiedere username e password&quot;">​</a></h3><p>Controlla:</p><ul><li>L&#39;URL è <code>https://your-domain.com/dav</code>.</li><li>Username e password corrispondono alle impostazioni WebDAV.</li><li>WebDAV è abilitato.</li><li>Il sito è accessibile via HTTPS.</li></ul><h3 id="la-navigazione-funziona-ma-l-upload-fallisce" tabindex="-1">La navigazione funziona, ma l&#39;upload fallisce <a class="header-anchor" href="#la-navigazione-funziona-ma-l-upload-fallisce" aria-label="Permalink to &quot;La navigazione funziona, ma l&#39;upload fallisce&quot;">​</a></h3><p>Controlla <code>Default channel</code>.</p><p>Gli upload WebDAV hanno bisogno di un canale di upload predefinito. Se manca, è disabilitato o configurato male, gli upload possono fallire.</p><h3 id="la-velocita-e-instabile" tabindex="-1">La velocità è instabile <a class="header-anchor" href="#la-velocita-e-instabile" aria-label="Permalink to &quot;La velocità è instabile&quot;">​</a></h3><p>Le prestazioni WebDAV dipendono da client, rete, numero di file e canale di upload predefinito.</p><p>Se una directory contiene molti file, organizzali in cartelle invece di tenerne troppi nello stesso punto.</p><h2 id="consigli-di-sicurezza" tabindex="-1">Consigli di sicurezza <a class="header-anchor" href="#consigli-di-sicurezza" aria-label="Permalink to &quot;Consigli di sicurezza&quot;">​</a></h2><ul><li>Usa HTTPS per l&#39;accesso WebDAV.</li><li>Imposta una password robusta.</li><li>Non condividere la password WebDAV con persone non fidate.</li><li>Disattiva WebDAV quando non lo usi.</li><li>Pulisci periodicamente i dispositivi WebDAV inutilizzati in Login Device Management.</li></ul><h2 id="dimensione-file-per-upload-webdav" tabindex="-1">Dimensione file per upload WebDAV <a class="header-anchor" href="#dimensione-file-per-upload-webdav" aria-label="Permalink to &quot;Dimensione file per upload WebDAV&quot;">​</a></h2><p>I client WebDAV non usano il flusso a chunk della pagina upload del browser. Per file oltre i limiti suggeriti sotto, usa la pagina web di upload.</p><table tabindex="0"><thead><tr><th>Canale di upload predefinito</th><th style="text-align:right;">Limite consigliato per singolo file WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const f=t(r,[["render",s]]);export{b as __pageData,f as default};
